mapper.select:
SELECT *
FROM book
WHERE id = #{id}
AND user_id = #{userId}

mapper.update:
UPDATE book
SET category = #{category},
	content = #{content},
	type = #{type},
	amount = #{amount},
	memo = #{memo}
WHERE id = #{id}
AND user_id = #{userId}

mapper.delete:
DELETE FROM book
WHERE id = #{id}
AND user_id = #{userId}
